from flask import Flask, request, jsonify
import logging
from werkzeug.security import check_password_hash, generate_password_hash
import re

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO, format='%(asctime)s - %(message)s')

# Dummy user data for demonstration
users = {
    "user@example.com": generate_password_hash("securepassword123")
}

def validate_email(email):
    # Simple regex for email validation
    return re.match(r"[^@]+@[^@]+\.[^@]+", email)

def log_attempt(email, ip, user_agent, success):
    logging.info(f"Login attempt - Email: {email}, IP: {ip}, User-Agent: {user_agent}, Success: {success}")

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    email = data.get('email', '')
    password = data.get('password', '')
    
    if not validate_email(email):
        return jsonify({"error": "Invalid email format"}), 400
    
    user_agent = request.headers.get('User-Agent', 'unknown')
    ip_address = request.remote_addr

    if email in users and check_password_hash(users[email], password):
        log_attempt(email, ip_address, user_agent, True)
        return jsonify({"message": "Login successful"}), 200
    else:
        log_attempt(email, ip_address, user_agent, False)
        return jsonify({"error": "Invalid credentials"}), 401

if __name__ == '__main__':
    app.run(debug=False)